# ROBUSTNESS PHASE F — Codegen boundary conditions and C compilation gate
# Manually written, not generated by testgen.py. Do not delete.
#
# Validates codegen.py rejects invalid inputs at precise boundaries and that
# the generated C files for all 11 ECU examples pass gcc -fsyntax-only.
# The GCC gate catches template regressions that silently produce broken C.
#
# Run: pytest test_robustness_F_codegen_limits.py -v
from __future__ import annotations

import os
import shutil
import subprocess
import sys
import tempfile
import textwrap

import pytest

EDS_ROOT  = os.path.abspath(os.path.join(os.path.dirname(__file__), "..", "..", "..", ".."))
CODEGEN   = os.path.join(EDS_ROOT, "tools", "codegen.py")

_TEMPLATES_OK = os.path.isdir(os.path.join(EDS_ROOT, "tools", "templates"))
_skip_no_tpl  = pytest.mark.skipif(
    not _TEMPLATES_OK,
    reason="Jinja2 templates not present (commercial-only, not in public repo)"
)

ALL_EXAMPLES = [
    "basic_ecu",
    "basic_ecu_doip",
    "basic_ecu_doip_freertos",
    "basic_ecu_freertos",
    "bms_ecu",
    "motor_controller_ecu",
    "ardep_ecu",
    "robot_joint_controller_ecu",
    "safeboot_ecu",
    "sensor_ecu",
    "sensor_ecu_freertos",
]

# Include paths for gcc -fsyntax-only against the EDS source tree.
# platform/zephyr is included for safeboot_ecu which pulls zephyr_flash_ops.h.
GCC_INCLUDE_FLAGS = [
    f"-I{EDS_ROOT}/core",
    f"-I{EDS_ROOT}/core/uds_services",
    f"-I{EDS_ROOT}/config",
    f"-I{EDS_ROOT}/transport",
    f"-I{EDS_ROOT}/transport/doip",
    f"-I{EDS_ROOT}/platform/zephyr",
]
GCC_DEFINE_FLAGS = ["-DUNIT_TEST=1", "-DEDS_MSG_BUF_MAX_STACK_BYTES=8192"]


def _run(cmd, **kwargs):
    return subprocess.run(cmd, capture_output=True, text=True, **kwargs)


def _codegen(yaml_content: str, extra_args: list | None = None):
    """Run codegen on yaml_content in a temp dir; return (returncode, output)."""
    with tempfile.TemporaryDirectory() as tmpdir:
        yaml_file = os.path.join(tmpdir, "config.yaml")
        out_dir   = os.path.join(tmpdir, "out")
        os.makedirs(out_dir)
        with open(yaml_file, "w") as f:
            f.write(yaml_content)
        cmd = [
            sys.executable, CODEGEN,
            "--config", yaml_file,
            "--out", out_dir,
            "--safety-wrappers", "--asil-level", "B", "--no-manifest",
        ]
        if extra_args:
            cmd.extend(extra_args)
        r = _run(cmd)
        return r.returncode, r.stdout + r.stderr


# ---------------------------------------------------------------------------
# Minimal valid YAML — used as a baseline for mutation tests
# ---------------------------------------------------------------------------

_VALID_BASE = textwrap.dedent("""\
    schema_version: 1
    metadata:
      ecu_name: "LimitTestECU"
      version:  "1.0.0"
      description: "Codegen boundary test ECU"
    timing:
      p2_server_max_ms:      25
      p2_star_server_max_ms: 5000
      s3_server_timeout_ms:  5000
    dids:
      - id:   "0xA001"
        name: "TestDID"
        access: [read]
        min_session: "default"
        read_security_level:  0
        write_security_level: 0
        data_length: 4
""")

_VALID_WRITABLE_BASE = textwrap.dedent("""\
    schema_version: 1
    metadata:
      ecu_name: "LimitTestECU"
      version:  "1.0.0"
      description: "Codegen boundary test ECU"
    timing:
      p2_server_max_ms:      25
      p2_star_server_max_ms: 5000
      s3_server_timeout_ms:  5000
    dids:
      - id:   "0xA001"
        name: "TestDIDWrite"
        access: [read, write]
        min_session: "extended"
        read_security_level:  0
        write_security_level: 1
        data_length: 4
""")


def _gen_n_dids_yaml(n: int, data_length: int = 4) -> str:
    """Generate a valid YAML with n unique read-only DIDs."""
    lines = textwrap.dedent("""\
        schema_version: 1
        metadata:
          ecu_name: "MultiDIDECU"
          version: "1.0.0"
          description: "DID count limit test"
        timing:
          p2_server_max_ms: 25
          p2_star_server_max_ms: 5000
          s3_server_timeout_ms: 5000
        dids:
    """)
    for i in range(n):
        did_id = f"0x{(0x1000 + i):04X}"
        lines += textwrap.dedent(f"""\
              - id:   "{did_id}"
                name: "DID{i:04d}"
                access: [read]
                min_session: "default"
                read_security_level:  0
                write_security_level: 0
                data_length: {data_length}
        """)
    return lines


# ---------------------------------------------------------------------------
# data_length boundary tests
# ---------------------------------------------------------------------------

@_skip_no_tpl
class TestDataLengthBoundaries:
    """Verify codegen accepts [1, 64] and rejects 0 and ≥ 65 under ASIL-B."""

    def test_data_length_zero_rejected(self):
        yaml = _VALID_BASE.replace("data_length: 4", "data_length: 0")
        rc, out = _codegen(yaml)
        assert rc != 0, "data_length: 0 must be rejected (not in [1, 4095])"
        assert "data_length" in out.lower() or "validation" in out.lower()

    def test_data_length_one_accepted(self):
        yaml = _VALID_BASE.replace("data_length: 4", "data_length: 1")
        rc, _ = _codegen(yaml)
        assert rc == 0, "data_length: 1 must be accepted (minimum valid value)"

    def test_data_length_64_accepted_asil_b(self):
        """64 is the ASIL-B maximum — must be accepted."""
        yaml = _VALID_BASE.replace("data_length: 4", "data_length: 64")
        rc, out = _codegen(yaml)
        assert rc == 0, f"data_length: 64 must be accepted under ASIL-B:\n{out}"

    def test_data_length_65_rejected_asil_b(self):
        """65 exceeds the ASIL-B static buffer limit — must be rejected."""
        yaml = _VALID_BASE.replace("data_length: 4", "data_length: 65")
        rc, out = _codegen(yaml)
        assert rc != 0, "data_length: 65 must be rejected under ASIL-B"
        assert "64" in out or "asil" in out.lower() or "safety" in out.lower()

    def test_data_length_4096_rejected(self):
        """4096 is outside the schema range [1, 4095] entirely."""
        yaml = _VALID_BASE.replace("data_length: 4", "data_length: 4096")
        rc, out = _codegen(yaml)
        assert rc != 0, "data_length: 4096 must be rejected (out of schema range)"


