# ---------------------------------------------------------------------------

class TestDuplicateAndReservedIDs:
    """Codegen must detect duplicates and reserved IDs as hard errors."""

    def test_duplicate_did_id_rejected(self):
        yaml = textwrap.dedent("""\
            schema_version: 1
            metadata:
              ecu_name: "DupTest"
              version: "1.0.0"
              description: "dup did"
            timing:
              p2_server_max_ms: 25
              p2_star_server_max_ms: 5000
              s3_server_timeout_ms: 5000
            dids:
              - id: "0xA001"
                name: "DID_A"
                access: [read]
                min_session: "default"
                read_security_level:  0
                write_security_level: 0
                data_length: 4
              - id: "0xA001"
                name: "DID_B"
                access: [read]
                min_session: "default"
                read_security_level:  0
                write_security_level: 0
                data_length: 4
        """)
        rc, out = _codegen(yaml)
        assert rc != 0, "Duplicate DID ID must be rejected"
        assert "0xa001" in out.lower() or "duplicate" in out.lower() or "already" in out.lower()

    def test_duplicate_routine_id_rejected(self):
        yaml = textwrap.dedent("""\
            schema_version: 1
            metadata:
              ecu_name: "DupRoutine"
              version: "1.0.0"
              description: "dup routine"
            timing:
              p2_server_max_ms: 25
              p2_star_server_max_ms: 5000
              s3_server_timeout_ms: 5000
            dids:
              - id: "0xA001"
                name: "BaseDID"
                access: [read]
                min_session: "default"
                read_security_level:  0
                write_security_level: 0
                data_length: 4
            routines:
              - id: "0xFF00"
                name: "TestRoutine"
                description: "first"
                min_session: "extended"
                security_level: 0
                support: [start]
              - id: "0xFF00"
                name: "TestRoutineDup"
                description: "duplicate"
                min_session: "extended"
                security_level: 0
                support: [start]
        """)
        rc, out = _codegen(yaml)
        assert rc != 0, "Duplicate routine ID must be rejected"

    def test_duplicate_dtc_code_rejected(self):
        yaml = textwrap.dedent("""\
            schema_version: 1
            metadata:
              ecu_name: "DupDTC"
              version: "1.0.0"
              description: "dup dtc"
            timing:
              p2_server_max_ms: 25
              p2_star_server_max_ms: 5000
              s3_server_timeout_ms: 5000
            dids:
              - id: "0xA001"
                name: "BaseDID"
                access: [read]
                min_session: "default"
                read_security_level:  0
                write_security_level: 0
                data_length: 4
            dtcs:
              - code: "0xC00100"
                description: "First"
                severity: "check_at_next_halt"
              - code: "0xC00100"
                description: "Duplicate"
                severity: "maintenance_only"
        """)
        rc, out = _codegen(yaml)
        assert rc != 0, "Duplicate DTC code must be rejected"

    def test_reserved_did_0x0000_rejected(self):
        yaml = _VALID_BASE.replace('"0xA001"', '"0x0000"')
        rc, out = _codegen(yaml)
        assert rc != 0, "Reserved DID 0x0000 must be rejected"
        assert "reserved" in out.lower() or "0x0000" in out.lower()

    def test_reserved_did_0xFFFF_rejected(self):
        yaml = _VALID_BASE.replace('"0xA001"', '"0xFFFF"')
        rc, out = _codegen(yaml)
        assert rc != 0, "Reserved DID 0xFFFF must be rejected"
        assert "reserved" in out.lower() or "0xffff" in out.lower()

    def test_invalid_access_value_rejected(self):
        yaml = _VALID_BASE.replace("access: [read]", 'access: [execute]')
        rc, out = _codegen(yaml)
        assert rc != 0, "Invalid access value 'execute' must be rejected"


