# ASIL-B write security constraints
# ---------------------------------------------------------------------------

@_skip_no_tpl
class TestASILBWriteSecurityConstraints:
    """write_security_level: 0 on a write-capable DID is a fatal ASIL-B error."""

    def test_write_did_zero_write_security_rejected(self):
        yaml = textwrap.dedent("""\
            schema_version: 1
            metadata:
              ecu_name: "ASILTest"
              version: "1.0.0"
              description: "asil write sec test"
            timing:
              p2_server_max_ms: 25
              p2_star_server_max_ms: 5000
              s3_server_timeout_ms: 5000
            dids:
              - id:   "0xA001"
                name: "UnsafeDID"
                access: [read, write]
                min_session: "extended"
                read_security_level:  0
                write_security_level: 0
                data_length: 4
        """)
        rc, out = _codegen(yaml)
        assert rc != 0, (
            "write-capable DID with write_security_level=0 must be rejected under ASIL-B")
        assert "security" in out.lower() or "asil" in out.lower() or "high-1" in out.lower()

    def test_write_did_nonzero_write_security_accepted(self):
        rc, out = _codegen(_VALID_WRITABLE_BASE)
        assert rc == 0, f"write_security_level=1 on write DID must be accepted:\n{out}"

    def test_readonly_did_with_zero_write_security_accepted(self):
        """write_security_level: 0 is fine for read-only DIDs."""
        rc, out = _codegen(_VALID_BASE)
        assert rc == 0, f"read-only DID with write_security_level=0 must be accepted:\n{out}"


