# ---------------------------------------------------------------------------
# Generated C compilation gate
# ---------------------------------------------------------------------------

@_skip_no_tpl
class TestGeneratedCCompilation:
    """
    For all 11 ECU examples, run gcc -fsyntax-only on each generated .c file.
    A template regression that produces broken C syntax fails here before it
    reaches a customer.
    """

    @pytest.fixture(autouse=True)
    def require_gcc(self):
        if not shutil.which("gcc"):
            pytest.skip("gcc not found in PATH")

    @pytest.mark.parametrize("ecu", ALL_EXAMPLES)
    def test_generated_c_syntax_clean(self, ecu):
        gen_dir = os.path.join(EDS_ROOT, "examples", ecu, "generated")
        if not os.path.isdir(gen_dir):
            pytest.skip(f"generated/ not found for {ecu} — run codegen first")
        c_files = [f for f in os.listdir(gen_dir) if f.endswith(".c")]
        if not c_files:
            pytest.skip(f"No .c files in generated/ for {ecu}")
        failures = []
        for c_file in sorted(c_files):
            cmd = (
                ["gcc", "-fsyntax-only"]
                + GCC_INCLUDE_FLAGS
                + [f"-I{gen_dir}"]
                + GCC_DEFINE_FLAGS
                + [os.path.join(gen_dir, c_file)]
            )
            r = _run(cmd)
            if r.returncode != 0:
                failures.append(f"{c_file}:\n{r.stdout + r.stderr}")
        assert not failures, (
            f"gcc -fsyntax-only failed for {ecu}:\n\n" + "\n\n".join(failures))


# ---------------------------------------------------------------------------
# Generated Python file integrity
# ---------------------------------------------------------------------------

@_skip_no_tpl
class TestGeneratedPythonIntegrity:
    """Verify no Jinja2 template artifacts remain in generated .py files."""

    JINJA2_ARTIFACTS = ("{{", "}}", "{%", "%}", "{#", "#}")

    @pytest.mark.parametrize("ecu", ALL_EXAMPLES)
    def test_no_jinja2_artifacts_in_generated_py(self, ecu):
        test_dir = os.path.join(EDS_ROOT, "examples", ecu, "generated", "tests")
        if not os.path.isdir(test_dir):
            pytest.skip(f"tests/ not found for {ecu}")
        # Exclude manually-written robustness files — they contain Jinja2 syntax
        # in YAML string literals by design.
        py_files = [
            f for f in os.listdir(test_dir)
            if f.endswith(".py") and not f.startswith("test_robustness_")
        ]
        if not py_files:
            pytest.skip(f"No .py files for {ecu}")
        violations = []
        for py_file in sorted(py_files):
            path = os.path.join(test_dir, py_file)
            with open(path) as fh:
                content = fh.read()
            for artifact in self.JINJA2_ARTIFACTS:
                if artifact in content:
                    violations.append(f"{py_file}: contains '{artifact}'")
        assert not violations, (
            f"Jinja2 template artifacts found in {ecu} generated Python:\n"
            + "\n".join(violations))

    @pytest.mark.parametrize("ecu", ALL_EXAMPLES)
    def test_generated_conftest_importable(self, ecu):
        """Generated conftest.py must be importable without errors."""
        conftest_path = os.path.join(
            EDS_ROOT, "examples", ecu, "generated", "tests", "conftest.py")
        if not os.path.isfile(conftest_path):
            pytest.skip(f"conftest.py not found for {ecu}")
        r = _run([sys.executable, "-c",
                  f"import importlib.util; "
                  f"spec = importlib.util.spec_from_file_location('conftest_{ecu}', '{conftest_path}'); "
                  f"mod = importlib.util.module_from_spec(spec); "
                  f"spec.loader.exec_module(mod)"])
        assert r.returncode == 0, (
            f"conftest.py for {ecu} failed to import:\n{r.stdout + r.stderr}")
